import type { Metadata } from 'next';
import { Inter } from 'next/font/google';
import './globals.css';
import { Navigation } from '@/components/layout';

const inter = Inter({ subsets: ['latin'] });

export const metadata: Metadata = {
  title: 'MMS - Metro Mileage Management System',
  description: 'Railway Fleet Mileage Management and Optimization',
};

export default function RootLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  return (
    <html lang="en">
      <body className={inter.className}>
        <div className="min-h-screen bg-gray-50">
          <Navigation />

          {/* Main Content */}
          <main className="max-w-7xl mx-auto py-6 px-4 sm:px-6 lg:px-8">
            {children}
          </main>
        </div>
      </body>
    </html>
  );
}

'use client';

import React from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';

const navItems = [
  { href: '/', label: 'Dashboard' },
  { href: '/map', label: 'Map' },
  { href: '/allocation', label: 'Allocation' },
  { href: '/fleet', label: 'Fleet' },
  { href: '/balancing', label: 'Balancing' },
  { href: '/maintenance', label: 'Maintenance' },
];

/**
 * Main Navigation Component
 *
 * Provides navigation links to all main pages.
 * Highlights the current active page.
 */
export function Navigation() {
  const pathname = usePathname();

  return (
    <nav className="bg-white shadow-sm border-b border-gray-200">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between h-16">
          <div className="flex items-center">
            <Link href="/" className="flex items-center">
              <span className="text-xl font-bold text-primary-600">MMS</span>
              <span className="ml-2 text-sm text-gray-500 hidden sm:block">
                Metro Mileage Management
              </span>
            </Link>

            {/* Nav Links */}
            <div className="hidden md:flex ml-10 space-x-4">
              {navItems.map((item) => {
                const isActive = pathname === item.href ||
                  (item.href !== '/' && pathname.startsWith(item.href));

                return (
                  <Link
                    key={item.href}
                    href={item.href}
                    className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${
                      isActive
                        ? 'bg-primary-100 text-primary-700'
                        : 'text-gray-600 hover:bg-gray-100 hover:text-gray-900'
                    }`}
                  >
                    {item.label}
                  </Link>
                );
              })}
            </div>
          </div>

          {/* Demo Badge */}
          <div className="flex items-center">
            <span className="px-2 py-1 text-xs font-medium bg-amber-100 text-amber-800 rounded">
              DEMO
            </span>
          </div>
        </div>
      </div>
    </nav>
  );
}

