'use client';

import React from 'react';

interface KPICardProps {
  title: string;
  value: string | number;
  subtitle?: string;
  borderColor?: string;
  icon?: React.ReactNode;
  loading?: boolean;
  tooltip?: string;
  onClick?: () => void;
}

/**
 * KPI Card Component
 *
 * Displays a single KPI metric with title, value, and optional subtitle.
 * Uses EN 15380 railway terminology.
 */
export function KPICard({
  title,
  value,
  subtitle,
  borderColor = 'border-primary-500',
  icon,
  loading = false,
  tooltip,
  onClick,
}: KPICardProps) {
  return (
    <div
      className={`bg-white shadow rounded-lg p-4 border-l-4 ${borderColor} transition-all duration-200 hover:shadow-md ${onClick ? 'cursor-pointer' : ''}`}
      title={tooltip}
      onClick={onClick}
      role={onClick ? 'button' : undefined}
      tabIndex={onClick ? 0 : undefined}
    >
      <div className="flex items-center justify-between">
        <div className="text-sm font-medium text-gray-500">{title}</div>
        {icon && <div className="flex-shrink-0">{icon}</div>}
      </div>
      <div className="mt-2">
        {loading ? (
          <div className="animate-pulse">
            <div className="h-8 bg-gray-200 rounded w-20"></div>
          </div>
        ) : (
          <div className="text-3xl font-bold text-gray-900">{value}</div>
        )}
      </div>
      {subtitle && !loading && (
        <div className="mt-1 text-sm text-gray-500">{subtitle}</div>
      )}
    </div>
  );
}

import { DashboardKPIs, DepotCapacityCards, MaintenanceAlerts } from '@/components/dashboard';

export default function Home() {
  return (
    <div className="space-y-6">
      <div className="bg-white shadow rounded-lg p-6">
        <h1 className="text-2xl font-bold text-gray-900">
          MMS Dashboard
        </h1>
        <p className="mt-2 text-gray-600">
          Railway Fleet Mileage Management System - Demo Version
        </p>
      </div>

      {/* Fleet Summary KPIs - Story 2.1 */}
      <section>
        <h2 className="text-lg font-semibold text-gray-700 mb-4">Fleet Overview</h2>
        <DashboardKPIs />
      </section>

      {/* Depot Capacity Cards - Story 2.3 */}
      <section>
        <h2 className="text-lg font-semibold text-gray-700 mb-4">Depot Capacity</h2>
        <DepotCapacityCards />
      </section>

      {/* Maintenance Alerts - Story 2.4 */}
      <section>
        <h2 className="text-lg font-semibold text-gray-700 mb-4">Maintenance Alerts</h2>
        <MaintenanceAlerts />
      </section>
    </div>
  );
}

